    STR_VOLUME_CONTROLS = 'ГҗЕЎГҗВөГ‘вӮ¬Г‘Ж’ГҗВІГҗВ°ГҗВҪГҗВҪГ‘ВҸ ГҗВ·ГҗВІГ‘Ж’ГҗВәГҗВҫГҗВј';
    STR_AUDIO_ALL = 'ГҗВЈГҗВІГ‘вҖ“ГҗВјГҗВәГҗВҪГ‘Ж’Г‘вҖҡГҗВё ГҗВІГҗВөГ‘ВҒГ‘Е’ ГҗВ·ГҗВІГ‘Ж’ГҗВә';
    STR_AUDIO_ALL_ENA = 'ГҗВЈГ‘ВҒГ‘вҖ“ ГҗВҙГҗВ¶ГҗВөГ‘вӮ¬ГҗВөГҗВ»ГҗВ° ГҗВ·ГҗВІГ‘Ж’ГҗВәГ‘Ж’ Г‘Ж’ГҗВІГ‘вҖ“ГҗВјГҗВәГҗВҪГҗВөГҗВҪГҗВҫ';
    STR_AUDIO_ALL_100 = 'ГҗвҖ”ГҗВІГ‘Ж’ГҗВә Г‘Ж’Г‘ВҒГ‘вҖ“Г‘вҖҰ ГҗВҪГҗВ° 100%';
