    UserLiveFeed_CheckIfIsLiveSTop();

    if (UserLiveFeed_ObjNotNull(pos)) Main_RemoveClass(UserLiveFeed_ids[0] + pos + '_' + UserLiveFeed_FeedPosY[pos], UserLiveFeed_FocusClass);
